`define INOUT ref
module automatic top;
  task automatic update(`INOUT bit flag, input bit upflag);
    flag = upflag ? 1 : flag;
  endtask
  bit my_flag;
  initial begin
    update(my_flag, 1);
    $display("flag=%d", my_flag);
    update(my_flag, 0);
    $display("flag=%d", my_flag);
  end
endmodule
